import{c as t,Q as n,j as e,m as r}from"./chunks/framework.DpF7k2f3.js";const _=JSON.parse('{"title":"第9章 LangChain実践","description":"","frontmatter":{"outline":"deep"},"headers":[],"relativePath":"ja/part3-practice/chapter9.md","filePath":"ja/part3-practice/chapter9.md"}'),i={name:"ja/part3-practice/chapter9.md"};function p(o,a,l,h,c,s){return n(),e("div",null,[...a[0]||(a[0]=[r('<h1 id="第9章-langchain実践" tabindex="-1">第9章 LangChain実践 <a class="header-anchor" href="#第9章-langchain実践" aria-label="Permalink to &quot;第9章 LangChain実践&quot;">​</a></h1><h2 id="本章で学べること" tabindex="-1">本章で学べること <a class="header-anchor" href="#本章で学べること" aria-label="Permalink to &quot;本章で学べること&quot;">​</a></h2><p>みんな实战の時間だ！</p><p>前面我们打好了基础——会调用大模型了（第5章）、知道怎么给AI接知识库了（第6章）、也搞明白了Agent是怎么工作的（第7章）。现在是时候把这些能力<strong>串起来变成真正能用的もの</strong>了。</p><p>この章ではLangChainを解説します——現在最も人気のAIアプリ開発フレームワーク。</p><p>正直に言います：<strong>LangChainは入门简单、用好难</strong>。公式のチュートリアルはHello World级别なのに、本番環境に投入すると思っていたより様々な问题が起きてしまう：バージョン非兼容、デバッグ難しい、パフォーマンスが悪い等等...</p><p>でも！LangChain依然是目前最主流的AI应用开发框架，学会它找工作加分、项目効率翻倍。而且2025-2026年、LangChainは<strong>LangGraph</strong>を发表、这东西直接把复杂Agent编排变成了声明式编程——就像从汇编进化到Python一样爽。</p><p>因此この章では：</p><ul><li>LangChainアーキテクチャとコアモジュールの快速チェック</li><li>LCELの深掘り——LangChainの真髄，必须搞透</li><li><strong>見せ場：LangGraph</strong>——2026年Agent開発標準ツール，我给你们掰开了揉碎了讲</li><li>RAG实现をトイから本番级へ升级</li><li>マルチツールAgentの深掘り</li></ul><hr><blockquote><p><strong>全文の翻訳は後日公開予定、しばらくお待ちください。中文版は今すぐ読めます。</strong></p><p>中文原文：<a href="/jumpstart-ai/zh/part3-practice/chapter9.html">中文版阅读</a></p></blockquote>',11)])])}const d=t(i,[["render",p]]);export{_ as __pageData,d as default};
